parameters.jsCode:
const input = $input.first().json;

// The AI Agent stores structured data inside `output`
const plan = input.output || input;

const searchQueries = plan.search_queries || [];

return searchQueries.map((item, index) => {
  return {
    json: {
      query_index: index + 1,
      query: item.query,
      category: item.category || "uncategorized",
      priority: item.priority || "medium",

      company: plan.company,
      role_level: plan.role_level,
      industry: plan.industry,
      research_depth: plan.research_depth,

      research_objectives: plan.research_objectives,
      source_categories: plan.source_categories,
      interview_angles: plan.interview_angles,
      must_find_signals: plan.must_find_signals
    }
  };
});

const searchItems = $input.all();
const flattened = [];

for (let i = 0; i < searchItems.length; i++) {
  const data = searchItems[i].json;

  // Pull original query context from the Extract Search Queries node
  const originalContext = $('Extract Search Queries').all()[i]?.json || {};

  const results = data.results || [];

  for (const result of results) {
    flattened.push({
      json: {
        company: originalContext.company || "unknown",
        role_level: originalContext.role_level || "unknown",
        industry: originalContext.industry || "unknown",
        research_depth: originalContext.research_depth || "unknown",

        source_query: originalContext.query || data.query || "",
        source_category: originalContext.category || "uncategorized",
        source_priority: originalContext.priority || "medium",

        title: result.title || "",
        url: result.url || "",
        snippet: result.content || "",
        tavily_score: result.score || 0,
        raw_content: result.raw_content || null
      }
    });
  }
}

return flattened;

const items = $input.all();

const seen = new Map();

function normalizeUrl(url) {
  if (!url) return "";

  try {
    const parsed = new URL(url);

    // Remove tracking params and fragments
    parsed.hash = "";
    parsed.searchParams.delete("utm_source");
    parsed.searchParams.delete("utm_medium");
    parsed.searchParams.delete("utm_campaign");
    parsed.searchParams.delete("utm_content");
    parsed.searchParams.delete("utm_term");
    parsed.searchParams.delete("fbclid");
    parsed.searchParams.delete("gclid");

    // Remove trailing slash
    return parsed.toString().replace(/\/$/, "");
  } catch (error) {
    return url.trim().replace(/\/$/, "");
  }
}

for (const item of items) {
  const source = item.json;
  const normalizedUrl = normalizeUrl(source.url);

  if (!normalizedUrl) continue;

  if (!seen.has(normalizedUrl)) {
    seen.set(normalizedUrl, {
      ...source,
      normalized_url: normalizedUrl,
      duplicate_count: 1,
      matched_queries: [source.source_query],
      matched_categories: [source.source_category]
    });
  } else {
    const existing = seen.get(normalizedUrl);

    existing.duplicate_count += 1;

    if (source.source_query && !existing.matched_queries.includes(source.source_query)) {
      existing.matched_queries.push(source.source_query);
    }

    if (source.source_category && !existing.matched_categories.includes(source.source_category)) {
      existing.matched_categories.push(source.source_category);
    }

    // Keep the better Tavily score if duplicate appears with higher relevance
    if ((source.tavily_score || 0) > (existing.tavily_score || 0)) {
      existing.tavily_score = source.tavily_score;
      existing.snippet = source.snippet || existing.snippet;
      existing.title = source.title || existing.title;
    }
  }
}

return Array.from(seen.values()).map(source => ({
  json: source
}));

parameters.text:
=You are a source quality evaluator for a Product Manager interview research workflow.

Your job is to score ONE source for whether it should be included in a NotebookLM research packet for interview preparation.

Company: {{ $json.company }}
Target role level: {{ $json.role_level }}
Industry: {{ $json.industry }}
Research depth: {{ $json.research_depth }}

Source title: {{ $json.title }}
Source URL: {{ $json.url }}
Source snippet: {{ $json.snippet }}
Original search query: {{ $json.source_query }}
Source category: {{ $json.source_category }}
Tavily relevance score: {{ $json.tavily_score }}
Duplicate count: {{ $json.duplicate_count }}
Matched queries: {{ JSON.stringify($json.matched_queries) }}
Matched categories: {{ JSON.stringify($json.matched_categories) }}

Evaluate this source using these criteria:

1. PM interview usefulness
2. Company strategy insight
3. Product insight
4. Customer/user insight
5. Competitive/market insight
6. Credibility/authority
7. NotebookLM usefulness

Scoring guidance:
- 9-10: Must include. Highly useful, authoritative, specific, interview-relevant.
- 7-8: Strong include. Useful and relevant.
- 5-6: Maybe include. Some value but not essential.
- 3-4: Low value. Generic, shallow, or redundant.
- 1-2: Exclude. Spammy, irrelevant, outdated, or weak.

Return raw JSON only.
Do not use markdown.
Do not include explanations outside JSON.

parameters.jsCode:
const scoredItems = $input.all();
const originalSources = $('Deduplicate Sources').all();

return scoredItems.map((item, index) => {
  const score = item.json.output || item.json;
  const source = originalSources[index]?.json || {};

  return {
    json: {
      ...source,
      ...score
    }
  };
});

const items = $input.all();

function priorityWeight(priority) {
  const value = String(priority || "").toLowerCase();

  if (value === "high") return 3;
  if (value === "medium") return 2;
  if (value === "low") return 1;

  return 0;
}

const sorted = items.sort((a, b) => {
  const aJson = a.json;
  const bJson = b.json;

  const aScore = Number(aJson.source_quality_score || 0);
  const bScore = Number(bJson.source_quality_score || 0);

  const aPriority = priorityWeight(aJson.notebooklm_priority);
  const bPriority = priorityWeight(bJson.notebooklm_priority);

  const aTavily = Number(aJson.tavily_score || 0);
  const bTavily = Number(bJson.tavily_score || 0);

  const aDuplicates = Number(aJson.duplicate_count || 1);
  const bDuplicates = Number(bJson.duplicate_count || 1);

  // Sort descending by quality, priority, Tavily relevance, then duplicate signal
  return (
    bScore - aScore ||
    bPriority - aPriority ||
    bTavily - aTavily ||
    bDuplicates - aDuplicates
  );
});

return sorted.map((item, index) => ({
  json: {
    rank: index + 1,
    ...item.json
  }
}));

const sourceItems = $('Limit Top Sources').all();
const deepPacketItems = $('Generate NotebookLM Research Packet').all();

if (!sourceItems.length) {
  return [{ json: { error: "No sources available" } }];
}

const first = sourceItems[0].json;

const deepResearchPacket = deepPacketItems
  .map(item => item.json.output || item.json.text || item.json.response || "")
  .filter(Boolean)
  .join("\n\n---\n\n");

const topSources = sourceItems.map((item) => {
  const source = item.json;

  return {
    rank: source.rank,
    title: source.title,
    url: source.url,
    normalized_url: source.normalized_url,
    source_type: source.source_type,
    source_category: source.source_category,
    source_quality_score: source.source_quality_score,
    notebooklm_priority: source.notebooklm_priority,
    primary_value: source.primary_value,
    source_summary: source.source_summary,
    suggested_use: source.suggested_use,
    snippet: source.snippet,
    matched_queries: source.matched_queries || [],
    risk_flags: source.risk_flags || []
  };
});

const manifestMarkdown = `# ${first.company} PM Interview Research Source Manifest

## Interview Context

- Company: ${first.company}
- Target Role Level: ${first.role_level}
- Industry / Space: ${first.industry}
- Research Depth: ${first.research_depth}
- Total Sources Selected: ${topSources.length}

## Priority Sources for NotebookLM

${topSources.map(source => `
### ${source.rank}. ${source.title}

**URL:** ${source.url}

**Source Type:** ${source.source_type}

**NotebookLM Priority:** ${source.notebooklm_priority}

**Quality Score:** ${source.source_quality_score}/10

**Primary Value:** ${source.primary_value}

**Why This Source Matters:** ${source.source_summary}

**Suggested Use:** ${source.suggested_use}

**Available Source Snippet:** ${source.snippet || "No snippet available."}

`).join("\n")}

## Deep Source Research Packet

${deepResearchPacket || "No deep research packet generated."}
`;

return [
  {
    json: {
      company: first.company,
      role_level: first.role_level,
      industry: first.industry,
      research_depth: first.research_depth,
      source_count: topSources.length,
      top_sources: topSources,
      deep_research_packet: deepResearchPacket,
      manifest_markdown: manifestMarkdown
    }
  }
];

const doc = $('Create Research Packet Doc').first().json;
const manifest = $('Generate Source Manifest').first().json;

function cleanText(value) {
  return String(value || "")
    .replace(/\\\\n/g, "\n")
    .replace(/\\n/g, "\n")
    .replace(/\\\\t/g, "\t")
    .replace(/\\t/g, "\t")
    .replace(/\r\n/g, "\n")
    .replace(/\n{3,}/g, "\n\n")
    .trim();
}

const researchPacketMarkdown = `# ${manifest.company} Deep Research Packet

## Interview Context

- Company: ${manifest.company}
- Target Role Level: ${manifest.role_level}
- Industry / Space: ${manifest.industry}
- Research Depth: ${manifest.research_depth}
- Sources Selected: ${manifest.source_count}

---

## How to Use This Packet

Use this document as the primary source file for NotebookLM. Upload it into a NotebookLM notebook, then ask NotebookLM to generate interview themes, product strategy insights, likely PM questions, product sense drills, execution drills, and a 30-minute prep plan.

---

## Deep Source Research Packet

${manifest.deep_research_packet || "No deep research packet available."}

---

## Source Manifest

${manifest.manifest_markdown || ""}
`;

const cleanPacket = cleanText(researchPacketMarkdown);

return [
  {
    json: {
      document_id: doc.id,
      request_body: {
        requests: [
          {
            insertText: {
              location: {
                index: 1
              },
              text: cleanPacket
            }
          }
        ]
      }
    }
  }
];
